INSERT INTO quiz_companies (name, description) VALUES 
('MTN Nigeria', '<p>MTN Nigeria is the leading telecommunications company in Nigeria, offering mobile voice, data, and fintech services. They regularly recruit graduates for various positions including graduate trainee programs.</p><p><strong>Common Job Roles:</strong> Graduate Trainee, Network Engineer, Sales Executive, Customer Service</p><p><strong>Recruitment Process:</strong> Online application, aptitude test, interview, assessment center</p>'),
('GTBank', '<p>GTBank is one of Nigeria''s leading financial institutions, known for innovation in banking services. They offer competitive graduate programs for young professionals.</p><p><strong>Common Job Roles:</strong> Graduate Trainee, Relationship Officer, IT Specialist, Operations</p><p><strong>Recruitment Process:</strong> Online application, CBT, panel interview, final round</p>'),
('Shell Nigeria', '<p>Shell Nigeria is a major oil and gas company operating in Nigeria. They offer various graduate and experienced hire positions in technical and business roles.</p><p><strong>Common Job Roles:</strong> Graduate Engineer, Field Engineer, Commercial Analyst, HSE Officer</p><p><strong>Recruitment Process:</strong> Online application, psychometric tests, technical interview, final interview</p>'),
('Nigerian Navy', '<p>The Nigerian Navy provides career opportunities for Nigerians in various roles including naval officers, ratings, and civilian staff.</p><p><strong>Common Job Roles:</strong> Naval Officer, Seaman, Marine Engineer, Logistics</p><p><strong>Recruitment Process:</strong> Application, screening, physical test, interview, training</p>'),
('Nigerian Police', '<p>The Nigeria Police Force offers career opportunities for qualified Nigerians in various ranks and specialized units.</p><p><strong>Common Job Roles:</strong> Police Constable, Inspector, DSP, Commissioner</p><p><strong>Recruitment Process:</strong> Online application, screening, physical test, medical, training</p>');
